_2dPEr1DRlMAYu7wDOtcLE7pQI3E", "path": "https://firebasestorage.googleapis.com/v0/b/fine-elf-391717.appspot.com/o/ducks%2Fimagecards%2Fimages%2F1709901498892?alt=media&token=e00cfee2-54e2-4dec-88ae-196096ed80af", "created_at": "2024-03-08T12:38:27.000000Z", "updated_at": "2024-03-08T12:38:27.000000Z" }, "image_fit": "contain", "caption": null, "audio": null, "audio_duration": "00:00:00" }, "position": 6 }, { "id": "card_2dPEqzT2gBVsUfG8bAX9Ihyp3Hh", "type": "text", "cardable": { "content": "she defies people’s steriotypes about her by being a really good debater and equel rights activist. \n\nwhich are not the steriotypes of a dancer", "font_size": 19 }, "position": 7 }, { "id": "card_2dPEqyu1Xxy1cpvgPyFE19SbA9L", "type": "text", "cardable": { "content": "she is in the fourth fourth wave feminism \n\nwhat are the waves of feminism", "font_size": 32 }, "position": 8 }, { "id": "card_2dPEr0vXVBIQYjQjsUy6ugiyx4d", "type": "text", "cardable": { "content": "The first wave was the fight for the right to vote which hapeened in 1920", "font_size": 32 }, "position": 9 }, { "id": "card_2dPEr0eqAvVpdxluXmGBb5lEPp6", "type": "text", "cardable": { "content": "The second wave was the fight for sexual violence and aborsion", "font_size": 32 }, "position": 10 }, { "id": "card_2dPEqwOjaZOCMiv5oOoLH0Q33OD", "type": "text", "cardable": { "content": "But 1. And 2. Wave feminism were only for white women", "font_size": 32 }, "position": 11 }, { "id": "card_2dPEqw4ieu4kcb0WpkGlu7uccVG", "type": "text", "cardable": { "content": "Third wave was sexual freedom gender identity and the fight for color women’s movement", "font_size": 32 }, "position": 12 }, { "id": "card_2dPEqyNHWSAtqedTMkyms7WKQEO", "type": "text", "cardable": { "content": "Fourth wave is the so-me movement it’s mostly the same as third wave and the me too movement and because of the world right the fight for lgbtq rights.", "font_size": 32 }, "position": 13 }, { "id": "card_2dPEqyhUTPA8yK0u7cNzT1QwJad", "type": "text", "cardable": { "content": "She released a book in 2017 called Ludermanifestet. Which Got relesed in 2017 The same year as The Harvey Weinstein trial.", "font_size": 32 }, "position": 14 }, { "id": "card_2dPEr1IvAhRpEl7bA4QHNg4DrKW", "type": "text", "cardable": { "content": "where is she now", "font_size": 32 }, "position": 15 }, { "id": "card_2dPEqwyp190nM60CJZ94MzfUNK7", "type": "text", "cardable": { "content": "Twerk Queen Louise is one of the most popular instagram influencers in denmark", "font_size": 32 }, "position": 16 }, { "id": "card_2dPEr2DlcWBuX4voxL8LeajvSWk", "type": "text", "cardable": { "content": "has a podcast about how to not have shame in your body", "font_size": 32 }, "position": 17 }, { "id": "card_2dPEqwBqQB1QwDYsGzTqCnfYhSV", "type": "text", "cardable": { "content": "You are not what the world tells you you are.", "font_size": 32 }, "position": 18 }, { "id": "card_2dPEr0TQRUef1DmcD0YMRXgiyu8", "type": "image", "cardable": { "image": { "id": "file_2dPEqzSFaKXbAArLJdjqA39BxiP", "path": "https://firebasestorage.googleapis.com/v0/b/fine-elf-391717.appspot.com/o/ducks%2Fimagecards%2Fimages%2F1709901503501?alt=media&token=d83f24af-0d80-41d3-a262-73d3f6f3546b", "created_at": "2024-03-08T12:38:27.000000Z", "updated_at": "2024-03-08T12:38:27.000000Z" }, "image_fit": "contain", "caption": null, "audio": null, "audio_duration": "00:00:00" }, "position": 19 }], "created_by": { "id": "user_2dOo56kXgHVpjeO699mLqRKLxIq", "profile_picture": null, "first_name": "Sebastian", "last_name": "Gittins", "username": "sebabs", "bio": null, "birthday": null, "register_completed_at": "2024-03-08T08:58:33.000000Z", "created_at": "2024-03-08T08:58:19.000000Z", "updated_at": "2024-03-08T08:58:33.000000Z" }, "latest_topics": [{ "id": "topic_2dPEqx6aZTUDWAb1lpX2itrZYEh", "name": "feminism" }, { "id": "topic_2dPEqwS2Yr1yGoAL5XM7mDCpwAy", "name": "Denmark" }], "latest_locations": [], "nests": [{ "id": "nest_2dOo58ENafC4d79o5tJiXOuhZHR", "title": "duck65ead32b32c31's Personal Nest", 